var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"주변의 침식체는 모두 처리한 것 같사옵니다.","JPN":"周辺の侵食体はすべて片付けたと思います。","ENG":"It seems we've taken care of all the C.O.s nearby.","TWN":"似乎已全部清除周圍的侵蝕體了。"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"이제 거의 다 왔어. 서두르자!","JPN":"あと少しだ。急ごう！","ENG":"We're almost there now. Let's hurry!","TWN":"已經快到了，快走吧！"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"이것이... 낙원문?","JPN":"これが……楽園の門？","ENG":"This is... Avalon's Gate?","TWN":"這就是……樂園門？"},"stage":{"bg":"COLLOSEUM_ASH","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"왜 이렇게 된 거지? 분명 어제까지만 해도 멀쩡했는데?","JPN":"なんでこうなったの？　確かに昨日までは無事だったのに？","ENG":"What happened here? It was perfectly fine just yesterday.","TWN":"為什麼會變成這樣？明明昨天還好好的？"},"stage":{"bg":"COLLOSEUM_ASH","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"형체도 알아볼 수 없을 정도로 망가졌사옵니다.","JPN":"形も分からないほど壊れております。","ENG":"It's been destroyed so badly its shape is unrecognizable.","TWN":"已經損壞到無法辨識原形了。"},"stage":{"bg":"COLLOSEUM_ASH","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"대체 누가 이런 짓을...","JPN":"いったい誰がこんなことを……","ENG":"Who could have done something like this...","TWN":"到底是誰做的……"},"stage":{"bg":"COLLOSEUM_ASH","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"내가 폭파했다.","JPN":"私が爆破した。","ENG":"I destroyed it.","TWN":"是我炸毀的。"},"stage":{"bg":"COLLOSEUM_ASH","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"다이나...?","JPN":"ダイナ……？","ENG":"Daina...?","TWN":"黛娜……？"},"stage":{"bg":"COLLOSEUM_ASH","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"당신이 부쉈다고? 왜 그런 짓을 한 거지?","JPN":"君が？　なぜそんなことを？","ENG":"You destroyed it? Why would you do that?","TWN":"是你破壞的？為什麼要這麼做？"},"stage":{"bg":"COLLOSEUM_ASH","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"낙원에 출구 같은 건 어울리지 않으니까.","JPN":"楽園に出口なんて似合わないからだ。","ENG":"An exit doesn't suit the Promised Land.","TWN":"樂園不需要出口。"},"stage":{"bg":"COLLOSEUM_ASH","slots":{"L":null,"C":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"설마, 아우드라가 지시한 거야? 그 녀석이 부수라고 한 건가?","JPN":"まさか、アウドラの指示？　あいつに壊せと言われたの？","ENG":"Did Audra order you to do it? Did she tell you to destroy it?","TWN":"難道是奧德拉下的命令？是那傢伙叫你破壞的嗎？"},"stage":{"bg":"COLLOSEUM_ASH","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COLLOSEUM_ASH","slots":{"L":null,"C":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"그 아이는 내게 아무것도 지시한 적 없어.","JPN":"あの子が私に何かを指示したことはない。","ENG":"That child never ordered me to do anything.","TWN":"那孩子從未對我下達過任何指示。"},"stage":{"bg":"COLLOSEUM_ASH","slots":{"L":null,"C":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"오히려 이 출구를 만든 게 그 아이였지. 모든 주민들이 자기 운명을 스스로 선택하길 바란다면서 말이야.","JPN":"むしろこの出口を作ったのはあの子だ。すべての住民に、己の運命を自分で選択してほしいと。","ENG":"If anything, she was the one who created this exit. She said she wanted all the residents to choose their own fates.","TWN":"反而是她創造了這個出口，希望所有居民都能自行選擇自己的命運。"},"stage":{"bg":"COLLOSEUM_ASH","slots":{"L":null,"C":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"우리가... 운명을 선택하길 바랐다고요?","JPN":"わたくしたちに……運命を選択してほしい？","ENG":"She... wanted us to choose our own fates?","TWN":"希望我們……選擇命運？"},"stage":{"bg":"COLLOSEUM_ASH","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_HATE"},"C":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"...분에 넘치는 소리지. 너희에게 운명을 선택할 기회를 주다니.","JPN":"……分不相応だろう。お前たちに運命を選ぶ機会を与えるなんて。","ENG":"...That's far too generous for the likes of you. Giving you the chance to choose your own fate.","TWN":"……竟然給你們選擇命運的機會，真是太奢侈了。"},"stage":{"bg":"COLLOSEUM_ASH","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_HATE"},"C":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"정작 자신은 자기 운명도 선택하지 못한 채, 그저 황금나무의 예언을 얌전히 기다리고 있으면서 말이야.","JPN":"自分自身で運命を選択できず、ただ黄金の木の予言を大人しく待っているくせにな。","ENG":"All while she herself could not choose her own fate and simply waited quietly for the prophecy of the Golden Tree.","TWN":"而她自己卻連自己的命運都無法選擇，只能靜靜等待黃金樹的預言。"},"stage":{"bg":"COLLOSEUM_ASH","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_HATE"},"C":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"황금나무의 예언이라면... 타기리온의 죽음을 말하는 거야?","JPN":"黄金の木の予言って……タギリオンの死のこと？","ENG":"If you mean the prophecy of the Golden Tree... are you talking about Thagirion's death?","TWN":"黃金樹的預言……你是指塔基里翁之死嗎？"},"stage":{"bg":"COLLOSEUM_ASH","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그녀가 황금나무의 예언을 받아들였다고?","JPN":"アウドラが黄金の木の予言を受け入れたの？","ENG":"She accepted the prophecy of the Golden Tree?","TWN":"她接受了黃金樹的預言？"},"stage":{"bg":"COLLOSEUM_ASH","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"허나 그 말은 이상하옵니다.","JPN":"ですが、それは変でございます。","ENG":"But that makes no sense.","TWN":"但這話很奇怪。"},"stage":{"bg":"COLLOSEUM_ASH","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SERIOUS"},"C":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"타기리온과 같은 존재인 그녀가 자신의 운명을 받아들였다면... 어찌하여 다른 세계를 멸망 시키면서까지 이런 허황된 낙원을 존속하려 한단 말입니까?","JPN":"タギリオンと同じ存在であるアウドラが自分の運命を受け入れたのなら……なぜ他の世界を滅ぼしてまでこのような虚構の楽園を存続させようとするのですか？","ENG":"If she, a being like Thagirion, accepted her own fate... Then why would she try to preserve such a hollow paradise even at the cost of destroying other worlds?","TWN":"像塔基里翁那樣的存在的她，如果接受了自己的命運……為何還要為了維持這個虛假的樂園而毀滅其他世界呢？"},"stage":{"bg":"COLLOSEUM_ASH","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_IDLE"},"C":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"너도 알잖아, 죄인 모르스.","JPN":"お前も分かってるじゃないか。罪人モールス。","ENG":"You already know the answer, don't you, sinner Mors.","TWN":"你也知道罪人莫爾斯吧？"},"stage":{"bg":"COLLOSEUM_ASH","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_IDLE"},"C":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"우린 모두 정해진 운명 안에서 발버둥 칠 뿐이야.","JPN":"私たちは皆、定められた運命の中でもがくだけだ。","ENG":"We're all just struggling within the bounds of the fate that's been decided for us.","TWN":"我們都只是在既定命運中掙扎罷了。"},"stage":{"bg":"COLLOSEUM_ASH","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_IDLE"},"C":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"적어도 그 결말로 이르는 과정에, 후회만은 남기지 않으려는 거지.","JPN":"せめてその結末に至る過程に後悔を残さないように。","ENG":"At the very least, we're trying not to leave behind any regrets along the path that leads to that ending.","TWN":"至少在走向結局的過程中不後悔。"},"stage":{"bg":"COLLOSEUM_ASH","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_IDLE"},"C":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COLLOSEUM_ASH","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"선배님! 거의 다 왔어요. 조금만 참으세요.","JPN":"先輩！　もうすぐです。あと少しだけ頑張ってください。","ENG":"Shiyoon! We're almost there. Just hold on a little longer.","TWN":"前輩！快到了，再撐一下！"},"stage":{"bg":"PATH","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"하하... 저도 그렇게 믿고 싶지만, 열 걸음 걸을 때마다 거의 다 왔다고 하시면 신뢰도가 떨어지는데요.","JPN":"ハハ……僕もそう信じたいですが、10歩ごとに同じことを言われると信頼が揺らいできますね。","ENG":"Haha... I'd like to believe that too, but if you keep saying we're almost there every ten steps, it starts to lose credibility.","TWN":"哈哈……我也想相信你啊。但你每走十步就說快到了，我對你的信賴度會下降啊。"},"stage":{"bg":"PATH","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"아까부터 워치의 바늘이 제멋대로 움직이고 있어. 이터니움을 보충하려 해도 반응이 없고.","JPN":"さっきからウォッチの針が勝手に動いてる。エタニウムを補充しようとしても反応がないし。","ENG":"The Watch's hands have been moving on their own for a while now. Even when I try to replenish Eternium, there's no response.","TWN":"從剛才開始手錶的指針就亂跳，就算補充永恆之金也沒有反應。"},"stage":{"bg":"PATH","slots":{"L":null,"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_HATE"}}}},{"id":"L41_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"우리의 존재가 옅어지는 탓에 CRF가 감응하지 못하는 거겠지. 능력은 아끼고 최대한 무기를 써.","JPN":"私たちの存在が薄くなったせいでCRFが感応できないんだろう。能力は使わず、なるべく武器を使え。","ENG":"It's probably because our existence is fading, so the CRF can't respond. Conserve your abilities and rely on your weapons as much as possible.","TWN":"因為我們的存在正在減弱，CRF無法感應吧。節省能力，盡量使用武器。"},"stage":{"bg":"PATH","slots":{"L":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_HATE"}}}},{"id":"L42_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"카운터인 우리가 힘을 못 쓸 정도라면...","JPN":"カウンターの私たちが力を使えないってことは……","ENG":"If even we Counters can't use our strength properly...","TWN":"如果連制裁者都無法發揮力量……"},"stage":{"bg":"PATH","slots":{"L":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_IDLE"}}}}]`);export{e as default};